#include <iostream>
#include <cassert>
#include "732.cpp"

int main() {
    int data[6][6] = {
        {1, 2, 7, 8, 9, 6},
        {2, 2, 3, 4, 5, 6},
        {3, 2, 3, 4, 5, 6},
        {4, 2, 3, 4, 5, 6},
        {5, 2, 9, 8, 7, 6},
        {6, 2, 7, 4, 5, 6}
    };
    int pattern[3][3] = {
        {3, 4, 5},
        {3, 4, 5},
        {3, 4, 5}
    };
    assert(Exists(data, pattern) == true);

    int p2[3][3] = {{0}}; 
    assert(Exists(data, p2) == false);

    assert(Exists(NULL, NULL) == false);
    return 0;
}
